const TT = (moduleId, id, num, name, slug, tags, hookQ, hookI, blocks, rel, gaps, diff, svgStr, vaType) => ({
  trackKey: TRACK_KEY, moduleId, topicId: id, topicNumber: num, name, slug,
  metadata: { estimated_minutes: 50, difficulty: 4, prerequisites: [], tags },
  hook: { question: hookQ, insight: hookI },
  teaching: { blocks, visual_aid: { type: vaType, svg: svgStr, alt_text: `${name} architecture diagram.` } },
  interviewRelevance: rel, commonGaps: { gaps },
  prerequisites: [], estimatedMinutes: 50, difficulty: diff, xpReward: 80, visualizer: null,
});
const C = (section, heading, body) => ({ kind: "concept", section, heading, body });
const K = (section, heading, body) => ({ kind: "code", section, heading, body });
const G = (id, w, r, d) => ({ gap_id: id, what_students_get_wrong: w, remediation: r, detection_pattern: d });

const TOPICS = [
  // ─────────────────── FEATURE-FLAG / CONFIG SERVICE ───────────────────────
  TT("sysd_m12", "sysd_m12_t1", 1, "Design a Feature-Flag / Config Service", "design-feature-flag-service",
    ["case-study", "feature-flags", "config", "rollout"],
    "You want to ship a feature to 5% of users, instantly turn off a broken one without a deploy, and show different config to different segments — evaluated on every request across thousands of servers in microseconds. How do you build feature flags / dynamic config at scale?",
    "A CONFIG store holds flag definitions (on/off, % rollout, targeting rules); the config is DISTRIBUTED to all app instances/SDKs and cached LOCALLY so flags are EVALUATED locally in microseconds (no per-request network call) — deterministically (hash the user for % rollouts/targeting, like A/B assignment). Changes (including an instant KILL SWITCH) propagate via fast config push/poll. Local flag evaluation + fast consistent config distribution are the substance.",
    [
      C("requirements", "Requirements",
        "Functional: define FLAGS / dynamic CONFIG (boolean toggles, percentage ROLLOUTS, per-SEGMENT targeting, multivariate values) and change them at RUNTIME without redeploying; EVALUATE a flag for a given user/context to get its value; an instant KILL SWITCH to disable a feature; audit of changes. Non-functional: VERY LOW-LATENCY evaluation (flags are checked on nearly every request/render across the whole fleet — must be ~microseconds), FAST and CONSISTENT propagation of changes (a kill switch must take effect in seconds across all servers), high AVAILABILITY (flag evaluation must never break the app — fail safe), and SCALE (thousands of services/instances, many flags, huge eval volume). Clarify scope: a feature-flag / dynamic-config service (LaunchDarkly-style) — shares core machinery with the A/B testing platform (same deterministic assignment + config distribution). The defining challenges: (1) flag EVALUATION must be on the hot path of every request yet add ~no latency, which rules out a network call per check — so evaluation happens LOCALLY in the app/SDK against a locally-cached config, using DETERMINISTIC hashing for percentage rollouts/targeting (so the same user consistently gets the same value); and (2) CONFIG DISTRIBUTION — pushing flag changes (especially a kill switch) to thousands of running instances QUICKLY and CONSISTENTLY, so behavior is uniform and a bad feature can be killed in seconds. So the design centers on local low-latency evaluation + fast, consistent config distribution (with fail-safe defaults)."),
      K("estimation", "Capacity estimation (with numbers)",
        "Evaluations: flags checked on ~every request across thousands of instances -> billions/day.\n  -> must be LOCAL (in-process) eval, ~microseconds ; no network call per check.\nConfig size: hundreds-thousands of flag rules -> small ; cache the whole config locally.\nPropagation: a change (esp. kill switch) must reach all instances in seconds (push/stream).\nEvaluation: deterministic -> hash(user_id + flag) for % rollout/targeting (same user, same value).\nTakeaway: distribute a small config to all instances (cached, fast-propagated) + evaluate\nLOCALLY (deterministic hashing) -> microsecond evaluation + seconds-to-propagate changes."),
      C("hld", "High-level design",
        "A CONFIG/flag STORE holds flag DEFINITIONS — each flag's state (on/off), percentage ROLLOUT, and TARGETING rules (segments: by user attribute, region, plan, etc.), edited via a management UI/API with an AUDIT log. The config is DISTRIBUTED to every application instance via an SDK that CACHES the full flag config LOCALLY (in-memory), kept fresh by a fast propagation mechanism (a streaming/push connection, or polling) so changes arrive within seconds. EVALUATION happens LOCALLY in the SDK: given a flag + the current user/context, the SDK applies the rules against the cached config — for a PERCENTAGE rollout or targeting, it computes deterministically (HASH(user_id + flag_key) -> bucket -> in/out of the rollout %), so the same user consistently gets the same value and no server round-trip is needed (microsecond evaluation). A KILL SWITCH is just a config change (flag -> off) pushed instantly to all instances — disabling a feature everywhere in seconds without a deploy. FAIL-SAFE: if config is unavailable, the SDK uses sensible DEFAULTS (the app never breaks because of flags). Trace it: ops sets 'newCheckout' to 10% rollout -> config pushed to all SDKs -> on each request the SDK hashes the user -> 10% get newCheckout=on (consistently) -> a bug appears -> ops flips kill switch -> pushed in seconds -> feature off everywhere. Config store + fast distribution to cached SDKs + local deterministic evaluation + instant kill switch is the shape (shared with A/B testing)."),
      K("api", "API / flow",
        "manage: define flag { state, rollout %, targeting rules } -> config store (+ audit)\ndistribute: push/stream (or poll) config to all SDKs -> cached locally (fresh within seconds)\nevaluate (local, in SDK): value = rules(user/context) ;\n   % rollout/targeting -> bucket(hash(user_id + flag_key))  // deterministic, same user same value\nkill switch: set flag off -> push -> disabled everywhere in seconds (no deploy)\nfail-safe: config unavailable -> use code default (app never breaks)"),
      K("data_model", "Data model",
        "flags: key -> { state on/off, rollout %, targeting rules, variations, default }\nsegments: named targeting rules (by attribute/region/plan)\nconfig snapshot: the full flag set distributed to SDKs (small, cached locally)\naudit: who changed what flag when (governance)\nevaluation: derived (not stored) -> hash(user + flag) for % / targeting"),
      C("deep_dive", "Deep dive: local, low-latency flag evaluation",
        "The core requirement is evaluating flags on the hot path with ~zero latency, which dictates LOCAL evaluation. The naive design — call a flag service over the network for each flag check — is fatal: flags are checked on nearly every request (often many per request) across the whole fleet, so a network round-trip per check would add latency and a hard dependency (the flag service down = the app down). Instead, the SDK embedded in each app instance CACHES the entire flag config LOCALLY (it's small) and EVALUATES flags IN-PROCESS in microseconds — no network call on the hot path. DETERMINISTIC EVALUATION for rollouts/targeting: for a PERCENTAGE rollout (10% of users), the SDK computes a deterministic bucket — HASH(user_id + flag_key) -> a value in [0,1) -> in the rollout if < 0.10 — so (a) it's consistent/STICKY (the same user always gets the same value, no flapping), (b) it needs no stored per-user state (pure computation, like A/B assignment), and (c) including the flag_key makes rollouts independent across flags. TARGETING applies rule predicates (user.country == 'US', user.plan == 'pro') locally against the context. FAIL-SAFE DEFAULTS: flag evaluation must NEVER break the app — if the cached config is missing/stale or the SDK errors, it returns a hardcoded DEFAULT value (the feature's safe state), so the flag system is never a single point of failure for the application. This local-eval model is exactly the A/B-testing assignment machinery (deterministic hashing + cached config), which is why feature flags and experiments share infrastructure. In-process evaluation against cached config, deterministic hashing for rollouts/targeting, and fail-safe defaults is the evaluation core interviewers probe (and why 'call the flag API per check' is wrong)."),
      C("deep_dive", "Deep dive: config distribution & consistency",
        "The other half is getting flag CHANGES to thousands of running instances QUICKLY and CONSISTENTLY — critical because a KILL SWITCH is worthless if it takes minutes to propagate. DISTRIBUTION mechanism: the config service pushes updates to all connected SDKs — typically a STREAMING/push connection (the SDK holds an open connection and receives changes in real time, e.g. SSE/WebSocket) for low-latency propagation (seconds), with POLLING as a fallback (SDK periodically fetches the latest config, simpler but with a polling-interval delay). On change, the new config (or a delta) is fanned out to all SDKs, which atomically swap their cached config. SPEED: a kill switch / urgent change must reach the whole fleet in SECONDS, so push/streaming is preferred for fast propagation. CONSISTENCY: ideally all instances flip at ~the same time so behavior is uniform — but distribution is inherently eventually consistent (some instances update slightly before others during the brief propagation window), which is acceptable for flags (a few seconds of mixed behavior is fine) as long as it's FAST and eventually uniform; the deterministic per-user evaluation ensures a given user gets a consistent value from whichever instance serves them once config has propagated. SCALE of distribution: thousands/millions of SDK connections -> the config-delivery layer must fan out efficiently (often via a CDN/edge or a connection-fanout tier, like presence/pub-sub). VERSIONING + AUDIT: config is versioned (rollback a bad change), and changes are audited (who/what/when) for governance. CACHING/edge: configs can be served from edge/CDN for fast initial fetch and to offload the origin. So fast (streaming) push + eventually-consistent-but-quick propagation + efficient fan-out at scale + versioning/audit is the distribution core — making the kill switch and rollouts actually work fleet-wide, which is what interviewers probe."),
      C("bottlenecks", "Bottlenecks & trade-offs",
        "EVALUATION LATENCY — must be microseconds on the hot path -> local in-process eval against cached config (never a per-check network call). PROPAGATION SPEED — kill switch must reach the fleet in seconds -> streaming/push (not slow polling). CONSISTENCY — eventual during the propagation window (brief mixed behavior) — acceptable for flags if fast. AVAILABILITY / fail-safe — the flag system must never break the app -> cached config + default values if config unavailable (no hard dependency). DISTRIBUTION SCALE — fan out config to millions of SDK connections -> edge/CDN + a fan-out tier. STALE CONFIG — bounded by propagation speed; deterministic eval keeps per-user consistency. Trade-offs: local SDK eval (microseconds, no hot-path dependency — config must be distributed/cached) vs central eval service (simple control — per-check latency + a hard dependency); streaming push (seconds propagation — connection management) vs polling (simple, robust — propagation lag); deterministic hashing (sticky, stateless rollouts) vs random/stored assignment (flexible — lookup/flap); fail-safe defaults (resilient — must define safe defaults) vs fail-closed (risk app breakage); edge/CDN config delivery (fast/scalable — slight extra staleness) vs direct (simpler, less scalable). Closing signal: a config/flag store edited at runtime + fast (streaming) distribution to SDKs that cache config locally and EVALUATE flags in-process with deterministic hashing (sticky % rollouts/targeting) and fail-safe defaults, with an instant kill switch (config push) and audit/versioning — microsecond evaluation + seconds-to-propagate changes, never breaking the app (and sharing machinery with A/B testing)."),
      C("deep_dive", "Deep dive: relation to A/B testing, governance & operations",
        "Operationally feature flags + dynamic config are foundational release infrastructure. Relation to A/B testing: feature flags and experiments share the SAME assignment (deterministic hashing) + config-distribution machinery — a flag is essentially a rollout, an experiment adds measurement (exposure logging + statistical analysis); many platforms unify them, so a percentage rollout can become an A/B test by logging exposures and outcomes. Progressive delivery: ramp a feature 1% -> 5% -> 25% -> 100% (grow the rollout %), with a kill switch for instant rollback — flags decouple DEPLOY (ship code dark) from RELEASE (turn it on gradually), enabling safe, dark launches, canary-by-flag, and operational toggles (circuit breakers, config knobs). Targeting & segments: rules by user attributes, plan, region, % — reusable segments; sometimes individual user overrides (allowlist). SDKs: client + server SDKs evaluate locally, fail safe, and (for server SDKs) hold a streaming config; client SDKs may evaluate server-side or fetch per-user flags. Governance: audit logs, change approval, flag lifecycle (temporary flags should be cleaned up — stale flags are tech debt), permissions, and environments (dev/staging/prod configs). Consistency for a user across services: include a stable user id in evaluation so the same user gets the same value everywhere (deterministic). Dynamic config beyond flags: the same system serves runtime configuration values (limits, feature parameters) changeable without deploy. Edge/CDN distribution + a streaming fan-out tier handle scale. Observability: evaluation latency (should be ~0/local), config propagation lag (kill-switch effectiveness), SDK connection health, and flag-change audit are the SLOs. The spine holds: runtime-editable config store + fast streaming distribution to locally-caching SDKs + deterministic local evaluation + fail-safe defaults + kill switch, unified with A/B testing, governed and versioned."),
      C("deep_dive", "Common follow-ups & how it evolves",
        "Expect: 'How is a flag evaluated without adding latency?' LOCALLY in the SDK against a locally-cached config (in-process, microseconds) — never a network call per check (that adds latency + a hard dependency). '% rollout consistently?' deterministic hashing — bucket(hash(user_id + flag_key)) — so the same user always gets the same value (sticky), stateless. 'Kill switch fleet-wide in seconds?' push the config change via a streaming/push channel to all SDKs (polling is the slower fallback); they swap cached config — disabled everywhere without a deploy. 'Consistency during propagation?' eventually consistent over a brief window (mixed behavior for seconds) — acceptable for flags if fast; per-user value stays consistent via deterministic eval. 'What if the flag service is down?' fail-safe — use the cached config / hardcoded defaults; flags must never break the app. 'Relation to A/B testing?' same assignment + distribution machinery; a flag is a rollout, an experiment adds exposure logging + stats. 'Scale distribution?' edge/CDN + a streaming fan-out tier to millions of SDKs. 'Stale flags?' lifecycle/cleanup (tech debt). 'Targeting?' rule predicates on user attributes/segments, evaluated locally. Each returns to the spine: runtime config store + fast streaming distribution to cached SDKs + deterministic local evaluation + fail-safe defaults + kill switch."),
    ],
    "A feature-flag/config service tests LOCAL low-latency evaluation (SDKs cache the config and evaluate in-process in microseconds — never a network call per check — using deterministic hashing for sticky % rollouts/targeting, with fail-safe defaults so flags never break the app) plus FAST, CONSISTENT config distribution (streaming push so a kill switch propagates fleet-wide in seconds, eventually-consistent-but-quick), versioned/audited and sharing machinery with A/B testing. The signal is local deterministic evaluation + fast config distribution + kill switch, not 'call a flag API on every request'.",
    [
      G("per_check_network", "Calling a flag service over the network on every flag check.", "Evaluate LOCALLY in the SDK against cached config (microseconds, no hot-path dependency); distribute config to SDKs.", "Each flag check makes a network call; adds latency + a hard dependency on the flag service."),
      G("no_kill_switch_propagation", "No fast propagation — config changes take minutes (polling only).", "Use streaming/push so changes (esp. a kill switch) reach the fleet in seconds; polling is only a fallback.", "Relies on slow polling; a kill switch can't take effect quickly."),
      G("not_failsafe", "Flag evaluation that can break the app if config is unavailable.", "Fail safe — return hardcoded defaults / use cached config when the service is unreachable; flags must never be a SPOF.", "App errors/blocks when the flag service/config is down."),
    ],
    0.5, DIAG.flags, "Feature-flag / config service architecture"),

  // ─────────────────────── PUSH NOTIFICATION GATEWAY ───────────────────────
  TT("sysd_m14", "sysd_m14_t4", 4, "Design a Push Notification Gateway", "design-push-gateway",
    ["case-study", "notifications", "fan-out", "providers"],
    "When a breaking-news story drops, you must push a notification to 50 million phones within minutes — through Apple's and Google's gateways, which you don't control and which rate-limit you, while skipping the millions of dead device tokens. How do you build a push notification gateway at scale?",
    "A gateway receives notification requests, resolves the target users' DEVICE TOKENS, and FANS OUT delivery through platform PROVIDERS (APNs for iOS, FCM for Android/web) via a QUEUE + worker pool (async, batched, retried) — handling massive broadcast fan-out, provider rate limits, retries with backoff, and invalid-token cleanup. Delivery via providers + fan-out, plus scale/reliability/token management, are the substance.",
    [
      C("requirements", "Requirements",
        "Functional: SEND push notifications to users' devices (mobile/web); support targeting one user, a segment, or a broadcast to ALL users; deliver via the platform push services; templating/personalization; track delivery; respect user preferences/opt-outs. Non-functional: SCALE + huge FAN-OUT (a broadcast = tens of millions of devices in minutes), RELIABILITY (retry transient failures; don't lose notifications), efficient PROVIDER integration (you must go through APNs/FCM, which you don't control and which throttle you), and DEVICE-TOKEN management (tokens expire/become invalid). Clarify scope: a push-notification gateway/service (the system that delivers pushes, not the app logic that decides to send them). The defining challenges: (1) DELIVERY must go through external PLATFORM PROVIDERS — Apple Push Notification service (APNs) for iOS, Firebase Cloud Messaging (FCM) for Android/web — you can't push directly to a phone; you send to the provider with the device's TOKEN, and they deliver — so the system integrates with these providers (their protocols, rate limits, and feedback); (2) massive FAN-OUT — one logical notification (especially a broadcast) maps to millions of individual device sends, an enormous fan-out that must be done efficiently and asynchronously; and (3) TOKEN management + RELIABILITY — device tokens expire/become invalid (apps uninstalled), providers throttle and transiently fail, so you need retries, invalid-token cleanup, and rate-limit handling. So the design centers on provider-based delivery + fan-out via a queue/worker pool, with scale, reliability, and token management."),
      K("estimation", "Capacity estimation (with numbers)",
        "Broadcast: 50M users * (1-2 devices) -> ~tens of millions of sends in minutes -> huge fan-out.\nProviders: APNs (iOS), FCM (Android/web) -> send per device token ; they rate-limit you.\nAsync: requests -> queue -> worker pool sends to providers (batched) -> retries on failure.\nTokens: device tokens expire/invalid (uninstalls) -> provider feedback -> clean up.\nThroughput: workers + provider connections sized to push millions/min within rate limits.\nTakeaway: resolve tokens -> queue -> worker fan-out to providers (batched, rate-limited,\nretried) -> devices ; manage invalid tokens ; scale workers + connections for broadcasts."),
      C("hld", "High-level design",
        "A notification REQUEST (to a user, segment, or broadcast) arrives at the gateway. It RESOLVES the target audience to DEVICE TOKENS (look up each user's registered device tokens + platform — iOS/Android/web — from a token store; for a broadcast, this is millions of tokens). The sends are placed on a QUEUE (async — delivery is decoupled from the request, which returns immediately and lets the queue absorb the burst). A pool of WORKERS consumes the queue and FANS OUT delivery through the platform PROVIDERS — sending each notification to APNs (iOS) or FCM (Android/web) with the device token (using the providers' batch/multicast APIs and persistent connections for throughput) — respecting provider RATE LIMITS. Providers return feedback: success, transient failure (RETRY with backoff), or INVALID/expired token (mark for CLEANUP so you stop sending to dead devices). Notifications are TEMPLATED/personalized, deduped, and delivery STATUS is tracked. User PREFERENCES/opt-outs are honored before sending. Trace a broadcast: 'send breaking-news to all' -> resolve to 40M device tokens -> enqueue -> workers send batches to APNs/FCM (rate-limited) over minutes -> devices buzz; invalid tokens reported -> removed from the store. Resolve tokens -> queue -> worker fan-out to APNs/FCM (batched, rate-limited, retried) -> devices, with token cleanup, is the shape."),
      K("api", "API / flow",
        "POST /notify { audience (user/segment/all), template, data } ->\n   resolve audience -> device tokens (+ platform) ; honor opt-outs\n   enqueue sends (async)\nworkers: pull -> batch by platform -> send to APNs (iOS) / FCM (Android/web) with tokens\n   success | transient fail -> retry w/ backoff | INVALID token -> mark for cleanup\nrate limiting: respect provider limits + per-user/app throttling\nstatus: track delivery ; token cleanup removes invalid/expired tokens"),
      K("data_model", "Data model",
        "device tokens: user -> [ { token, platform (iOS/Android/web), app, last_seen } ]  (registry)\nnotifications: id, audience, template/payload, status\nqueue: pending sends (per device) -> workers ; supports broadcast fan-out\nproviders: APNs / FCM connections + credentials + rate limits\npreferences: per-user opt-outs / categories / quiet hours\nfeedback: invalid/expired tokens -> cleanup"),
      C("deep_dive", "Deep dive: delivery via providers & fan-out",
        "The core is delivering through external PROVIDERS and handling massive FAN-OUT. PROVIDER DELIVERY: you cannot push directly to a device — each mobile/web platform has its own push service (APNs for Apple, FCM for Android + web push) that actually delivers to the device; your gateway sends a notification to the provider identified by the device's TOKEN (a per-device, per-app credential the device registered), and the provider routes it to the device (even waking the app). So the gateway is fundamentally an INTEGRATION + ROUTING layer to these providers: it maintains authenticated connections to APNs/FCM, speaks their protocols, uses their BATCH/multicast APIs (send to many tokens efficiently) and persistent/HTTP-2 connections (high throughput), and routes each send to the right provider by the device's platform. TOKEN RESOLUTION: a notification targets USERS, but delivery needs DEVICE TOKENS, so the gateway first resolves the audience to all their registered device tokens (a user may have multiple devices/platforms) from a token registry. FAN-OUT: one logical notification expands to MANY device sends — trivial for a single user, but a SEGMENT or BROADCAST expands to millions of device sends (huge fan-out). This is handled ASYNCHRONOUSLY: the request enqueues the sends and a WORKER POOL fans them out to the providers, so the request returns instantly and the heavy delivery happens in the background, with the QUEUE absorbing the burst and smoothing it over the workers' (and providers') capacity. Batching sends to the providers and parallelizing across workers/connections is how millions are delivered in minutes. Provider integration/routing (APNs/FCM by platform, batched, persistent connections) + token resolution + async worker fan-out over a queue is the delivery core interviewers probe (and why you can't 'just send to the phone')."),
      C("deep_dive", "Deep dive: scale, reliability & token management",
        "Around delivery sit scale, reliability, and token hygiene. SCALE / RATE LIMITS: providers (APNs/FCM) THROTTLE how fast you can send, and a broadcast is enormous, so the worker pool + provider connections are sized to push at the allowed rate, the queue buffers the backlog, and you AUTOSCALE workers for big sends — respecting provider rate limits (back off when throttled) and adding your own per-user/per-app throttling (don't spam a user). RELIABILITY: delivery to providers can transiently FAIL (provider hiccup, timeout), so workers RETRY with backoff (and the queue ensures a send isn't lost if a worker crashes — it's re-attempted); IDEMPOTENCY/dedup avoids sending the same notification twice on retry. PRIORITY: time-sensitive notifications (a message) jump ahead of bulk/marketing sends (priority queues). TOKEN MANAGEMENT (critical at scale): device tokens become INVALID constantly — apps are uninstalled, tokens rotate, devices reset — and the providers report these (FCM/APNs return 'invalid/unregistered token' on send, or via feedback channels); the gateway must CLEAN UP invalid tokens (remove them from the registry) so it stops wasting sends on dead devices (sending to millions of stale tokens is pure waste and can hurt your provider reputation) — token hygiene keeps the fan-out efficient. Tokens are REGISTERED/refreshed by the app on each launch (keeping the registry current). DELIVERY TRACKING: track sent/delivered/failed for analytics (true 'delivered' is limited — providers give best-effort feedback). PREFERENCES/opt-outs and quiet hours are enforced before sending (compliance + UX). So rate-limit-aware autoscaled workers + retries/idempotency + priority + aggressive invalid-token cleanup + preference enforcement is how the gateway scales reliably — the operational substance interviewers probe."),
      C("bottlenecks", "Bottlenecks & trade-offs",
        "MASSIVE FAN-OUT (broadcasts) — millions of sends -> async queue + autoscaled worker pool + provider batching; the queue absorbs the burst and delivery spreads over minutes. PROVIDER RATE LIMITS/throttling — you can't exceed APNs/FCM limits -> rate-aware sending + backoff + sized connections. INVALID TOKENS — sending to dead tokens is wasted effort and hurts reputation -> clean up invalid tokens from provider feedback. RELIABILITY — provider/transient failures -> retries with backoff + queue durability + idempotency. PRIORITY — urgent vs bulk -> priority queues. PROVIDER DEPENDENCY — you rely on external services (outages) -> retry/queue + graceful degradation. Trade-offs: async queue + workers (absorbs huge fan-out, scalable — 'queued' delay) vs synchronous (immediate, can't handle broadcasts); batch sends to providers (high throughput, efficient — slight latency) vs one-at-a-time (simple, slow); aggressive token cleanup (efficient fan-out, good provider standing — must process feedback) vs ignore (wasteful sends, reputation hit); priority queues (urgent fast, complexity) vs FIFO (simple, head-of-line blocking for bulk); store all tokens (full reach, hygiene needed) vs lazy cleanup (simpler, wasteful). Closing signal: resolve the audience to device tokens, enqueue sends, and fan them out via an autoscaled worker pool to platform providers (APNs/FCM, batched, persistent connections) within rate limits, with retries+backoff+idempotency for reliability, priority queues for urgency, and aggressive invalid-token cleanup from provider feedback — delivering massive notification fan-out reliably through providers you don't control."),
      C("deep_dive", "Deep dive: templating, preferences, analytics & operations",
        "Operationally a push gateway is large-scale delivery infrastructure many teams call. Notification composition: templates with personalization (per-user data), localization, and rich content (images/actions); the gateway renders the per-device payload per platform (APNs and FCM have different payload formats — translate accordingly). Audience resolution: targeting a SEGMENT requires resolving it to users -> device tokens, which can be a large batch job (integrate with a user/segment store); broadcasts stream tokens to the queue. Preferences & compliance: enforce per-user opt-outs, notification categories, quiet hours/time-zone-aware delivery, and frequency caps before sending (regulatory + UX — over-notifying drives uninstalls); respect platform rules. Multi-channel: often the same system also sends in-app, SMS, email, or web push (a unified notification service) — push is one channel; a preference/routing layer picks channels. Token lifecycle: apps register/refresh tokens on launch; the registry is kept current; invalid tokens pruned via provider feedback; multiple devices per user. Reliability & idempotency: durable queue, retries with backoff, dedup keys so a user isn't double-notified; dead-letter for permanent failures. Scheduling: scheduled/triggered sends (send at a time, or on an event). Analytics & feedback: track sent/failed (and opens, via app callbacks) for engagement metrics; A/B test notification content. Scale & isolation: per-app/tenant isolation + fair rate limiting so one big campaign doesn't starve transactional pushes; priority lanes (transactional > marketing). Provider abstraction: a provider-adapter layer so adding a platform (Huawei, web push) is pluggable, and provider outages are handled (retry/fallback). Observability: send throughput, provider latency/error/throttle rates, invalid-token rate, queue depth, and delivery/open rates are the SLOs. The spine holds: token resolution + async queued worker fan-out to providers (APNs/FCM) with batching/rate-limits/retries + invalid-token cleanup + preferences/priority, across channels, multi-tenant-fair."),
      C("deep_dive", "Common follow-ups & how it evolves",
        "Expect: 'How do you actually deliver to a phone?' through platform PROVIDERS — APNs (iOS) and FCM (Android/web) — you send to them with the device's TOKEN and they deliver; the gateway integrates with/routes to them (batched, persistent connections). 'A broadcast to 50M?' resolve to device tokens, enqueue, and FAN OUT via an autoscaled worker pool to the providers asynchronously (the queue absorbs the burst); delivery spreads over minutes within provider rate limits. 'Provider throttling?' rate-aware sending + backoff + sized connections; queue buffers. 'Dead/invalid tokens?' providers report them — clean them from the registry so you stop wasting sends (and protect your sender reputation); apps refresh tokens on launch. 'Reliability?' durable queue + retries with backoff + idempotency (no dupes); dead-letter permanent failures. 'Urgent vs marketing?' priority queues (transactional first). 'Don't spam users?' enforce opt-outs, categories, quiet hours, frequency caps before sending. 'Multiple devices/platforms?' resolve all of a user's tokens and route each to the right provider with the right payload format. 'Multi-channel?' a unified notification service (push/SMS/email/in-app). Each returns to the spine: resolve tokens -> queue -> worker fan-out to APNs/FCM (batched, rate-limited, retried) -> devices, with invalid-token cleanup + preferences/priority."),
    ],
    "A push notification gateway tests delivery through external PROVIDERS (APNs/FCM — you can't push directly; route by platform with device tokens, batched, persistent connections) and massive FAN-OUT via an async QUEUE + autoscaled worker pool (a broadcast = millions of sends), with provider RATE-LIMIT handling, retries+backoff+idempotency for reliability, priority lanes, preference/opt-out enforcement, and aggressive INVALID-TOKEN cleanup from provider feedback. The signal is provider-based delivery + queued worker fan-out + token management, not 'send directly to devices'.",
    [
      G("direct_to_device", "Trying to push directly to devices instead of via providers.", "Deliver through platform providers (APNs/FCM) using device tokens; the gateway integrates with + routes to them by platform.", "Sends notifications straight to phones; no APNs/FCM integration."),
      G("synchronous_broadcast", "Sending a broadcast synchronously / one send at a time.", "Resolve tokens, enqueue, and fan out asynchronously via an autoscaled worker pool (batched, rate-limited); the queue absorbs the burst.", "Loops over millions of users synchronously in the request; can't handle broadcast fan-out."),
      G("no_token_cleanup", "Ignoring invalid/expired device tokens.", "Process provider feedback and clean up invalid tokens — sending to dead tokens is wasteful and hurts sender reputation.", "Keeps sending to stale/uninstalled tokens; no cleanup from provider feedback."),
    ],
    0.5, DIAG.push, "Push notification gateway architecture"),

  // ───────────────── SOCIAL GRAPH (PEOPLE YOU MAY KNOW) ─────────────────────
  TT("sysd_m15", "sysd_m15_t1", 1, "Design a Social Graph (People You May Know)", "design-social-graph",
    ["case-study", "graph", "recommendations", "scale"],
    "A network with a billion users and tens of billions of friendships must answer 'who are my friends', 'are we connected', and — the hard one — 'people you may know': suggest friends-of-friends ranked by how many mutual connections you share. Computing that for everyone is enormous. How do you store the graph and generate PYMK at scale?",
    "Store the social graph as sharded ADJACENCY LISTS (or a graph DB) supporting 1st/2nd-degree connection queries; 'People You May Know' = find FRIENDS-OF-FRIENDS (2nd-degree) and RANK them by MUTUAL-connection count (+ other signals). Because that 2nd-degree traversal + ranking is expensive at billions of edges, PRECOMPUTE PYMK suggestions OFFLINE via batch graph processing and serve them cached. Graph storage + 2nd-degree queries + offline PYMK computation are the substance.",
    [
      C("requirements", "Requirements",
        "Functional: store the SOCIAL GRAPH (users as nodes, friendships/follows as edges); query a user's connections (friends), check if two users are connected, and find 2nd-degree connections; generate 'PEOPLE YOU MAY KNOW' (PYMK) recommendations — suggest users you're likely to know (typically friends-of-friends with many MUTUAL connections). Non-functional: HUGE scale (hundreds of millions–billions of users, tens of billions of edges), efficient CONNECTION queries (1st/2nd-degree), and PYMK generation at scale (relevant suggestions for everyone). Clarify scope: the social-graph storage + the PYMK recommendation. The defining challenges: (1) storing and querying a MASSIVE GRAPH — billions of nodes/edges that don't fit on one machine, so the graph must be SHARDED, and graph traversals (especially 2nd-degree: friends-of-friends) FAN OUT quickly (a user with 1000 friends each with 1000 friends -> a million 2nd-degree candidates) and can be costly, plus SUPERNODES (celebrities with millions of edges) skew things; and (2) PYMK COMPUTATION — the core recommendation is friends-of-friends ranked by MUTUAL-connection count (and other signals), which is a 2nd-degree traversal + aggregation per user that is far too expensive to compute on-demand at request time for everyone, so it's PRECOMPUTED OFFLINE via batch graph processing and served from a cache. So the design centers on sharded graph storage + connection queries + offline PYMK generation."),
      K("estimation", "Capacity estimation (with numbers)",
        "Users: ~1B nodes ; edges: tens of billions (avg hundreds of friends) -> doesn't fit one machine.\nStorage: adjacency lists (user -> friend ids) sharded by user ; or a graph DB.\n2nd-degree: 1000 friends * 1000 each = ~1M friends-of-friends candidates -> expensive fan-out.\nPYMK: friends-of-friends ranked by MUTUAL count -> heavy per-user computation.\n  -> precompute OFFLINE (batch graph processing) ; serve cached suggestions.\nSupernodes: celebrities (millions of edges) skew traversal -> special handling.\nTakeaway: shard the graph (adjacency lists), support 1st/2nd-degree queries, and PRECOMPUTE\nPYMK offline (friends-of-friends + mutual-count ranking) served from cache."),
      C("hld", "High-level design",
        "GRAPH STORAGE: model users as nodes and friendships as edges, stored as ADJACENCY LISTS (each user -> the list of their friend ids) in a scalable store (a sharded key-value/wide-column store, or a dedicated graph database), SHARDED by user across many machines (the graph is too big for one). This supports fast 1st-degree queries (a user's friends = read their adjacency list) and connection checks. PYMK GENERATION (the recommendation): for a user, the candidate suggestions are FRIENDS-OF-FRIENDS (2nd-degree connections not already friends), RANKED by the number of MUTUAL connections (how many of your friends are also their friends — the strongest 'you may know them' signal) plus other signals (shared schools/workplaces, contacts, location). Because computing this requires expanding each user's 2nd-degree neighborhood and counting mutuals — a heavy, fan-out-y graph computation — it is NOT done on-demand at request time for billions of users; instead PYMK is PRECOMPUTED OFFLINE by a BATCH GRAPH-PROCESSING job (over the whole graph, e.g. a distributed graph/MapReduce computation that finds friends-of-friends and mutual counts), and the resulting top suggestions per user are stored in a fast cache/store, SERVED instantly when the user opens 'People You May Know'. SUPERNODES (celebrities) get special handling to avoid skewing traversals. Trace it: store friendships as sharded adjacency lists -> nightly batch job computes friends-of-friends + mutual counts per user -> top PYMK candidates cached -> user opens app -> serve precomputed PYMK. Sharded adjacency-list graph + 1st/2nd-degree queries + offline-precomputed mutual-ranked PYMK served cached is the shape."),
      K("api", "API / flow",
        "store: user -> adjacency list (friend ids) ; sharded by user ; (or graph DB)\nqueries: friends(user) = read adjacency list ; connected(a,b)? ; 2nd-degree(user)\nPYMK (offline batch): for each user, friends-of-friends (2nd-degree, not already friends),\n   ranked by MUTUAL-connection count + signals (school/work/contacts) -> top-N\n   -> store/cache per user\nserve: GET /pymk -> precomputed suggestions (cached) ; refresh periodically\nedges: add/remove friendship -> update both adjacency lists"),
      K("data_model", "Data model",
        "nodes: users\nedges: friendships/follows -> adjacency lists (user -> [friend ids]), sharded by user\n  (undirected friendship = store both directions; directed follow = one)\nPYMK store: per-user precomputed suggestions (candidate + mutual count + score) -> cached\nsupernodes: high-degree users flagged for special handling\nsignals: shared school/work/contacts/location (for ranking)"),
      C("deep_dive", "Deep dive: graph storage & connection queries",
        "The foundation is storing a billion-node, tens-of-billions-edge graph and querying connections efficiently. STORAGE MODEL: the standard representation is ADJACENCY LISTS — each user maps to the list of their connections' ids — which makes the common queries cheap: a user's FRIENDS = read their adjacency list (one lookup), and CONNECTED(A,B)? = is B in A's list. This can live in a sharded KEY-VALUE / wide-column store (user_id -> friend ids) or a dedicated GRAPH DATABASE (optimized for traversals); the choice trades graph-native traversal power vs the simplicity/scale of a KV store. SHARDING: the graph is far too big for one machine, so it's PARTITIONED by user across many shards — friends(user) hits one shard, but a TRAVERSAL crossing users (2nd-degree) touches MANY shards (a user's friends live on various shards, and their friends elsewhere), making cross-shard traversals expensive (the fundamental hard part of distributed graphs — you can't co-locate everyone's neighborhood). 1st-DEGREE queries are fast (local list read); 2nd-DEGREE queries FAN OUT — friends-of-friends means reading all your friends' adjacency lists (potentially thousands of cross-shard reads, yielding up to ~a million candidates) — costly to do on demand. THE SUPERNODE PROBLEM: some nodes (celebrities, hugely-followed accounts) have MILLIONS of edges, so their adjacency list is huge and traversing through them explodes (a 2nd-degree path through a celebrity connects you to millions) — special handling is needed (cap/sample their edges in traversal, treat them separately, exclude them from mutual-friend signals since 'we both follow a celebrity' isn't meaningful). For undirected friendships you store BOTH directions (A->B and B->A) so each side's list is complete; follows are directed (one direction). Sharded adjacency-list storage + cheap 1st-degree / expensive cross-shard 2nd-degree queries + supernode handling is the storage core interviewers probe (and why a single relational table with self-joins doesn't scale to billions)."),
      C("deep_dive", "Deep dive: PYMK recommendation (friends-of-friends, mutual ranking, offline)",
        "PYMK is the signature feature and its key insight is that it's TOO EXPENSIVE to compute on-demand, so it's PRECOMPUTED OFFLINE. THE ALGORITHM (conceptually): for a user, the best 'people you may know' are typically FRIENDS-OF-FRIENDS (2nd-degree connections you're not already connected to), RANKED by the number of MUTUAL connections — if 15 of your friends are also friends with someone, you very likely know them (mutual-friend count is the strongest signal) — plus secondary signals (shared school/employer, imported contacts/phone book, same location/groups, interaction patterns). WHY OFFLINE: computing this requires, per user, expanding their 2nd-degree neighborhood (reading all friends' friend lists — millions of candidates across shards) and aggregating mutual counts — a heavy, fan-out-heavy computation; doing it on-demand for billions of active users would be infeasible (huge cross-shard traversal per request). So instead it's computed in BATCH OFFLINE: a distributed GRAPH-PROCESSING job (e.g. MapReduce / a graph-compute framework like Pregel/Giraph/Spark-GraphX) processes the WHOLE graph periodically — for every user, enumerate friends-of-friends and count mutuals (efficiently, e.g. for each user emit pairs of their friends as 'mutual' signals, then aggregate per candidate pair), rank, and store the TOP-N suggestions per user in a fast cache/store. SERVING is then trivial and instant: 'People You May Know' just reads the user's PRECOMPUTED list (cached) — no traversal at request time. FRESHNESS: the batch recompute runs periodically (daily/regularly) and can be supplemented with incremental updates for recent activity (a new friend can trigger updating suggestions). FILTERING: exclude already-connected, blocked, or dismissed users; cap supernode influence. This precompute-offline-serve-cached pattern (the same as recommendation systems) is the crux — heavy graph computation done in batch, cheap serving from cache — and exactly what interviewers probe (the wrong instinct is 'traverse the graph live per request')."),
      C("bottlenecks", "Bottlenecks & trade-offs",
        "GRAPH SCALE (billions of edges) — shard by user; the graph doesn't fit one machine. CROSS-SHARD 2nd-DEGREE TRAVERSAL — friends-of-friends fans out across many shards (expensive) -> precompute offline, don't traverse live. SUPERNODES — celebrities with millions of edges explode traversals + pollute mutual signals -> cap/sample/exclude them. PYMK COMPUTE COST — heavy per-user graph computation -> batch offline (graph-processing framework) + cache results. FRESHNESS — precomputed PYMK lags -> periodic recompute + incremental updates on new connections. WRITE consistency — a friendship updates two adjacency lists (both directions). Trade-offs: adjacency-list KV store (scales, simple 1st-degree, cheap — manual traversal logic) vs graph DB (native traversals, expressive — harder to scale to billions); precompute PYMK offline (instant serving, scalable — staleness + batch cost) vs compute on-demand (fresh — infeasible cross-shard traversal at scale); mutual-count ranking (strong signal, simple) vs richer ML ranking (better, costlier); supernode special-casing (correct/efficient — complexity) vs naive traversal (simple — explodes); store both edge directions (fast bidirectional reads — double writes) vs one direction (less storage — slower reverse queries). Closing signal: store the social graph as sharded adjacency lists (or a graph DB) for fast 1st-degree queries, handle supernodes, and generate PYMK as friends-of-friends ranked by mutual-connection count (+ signals) PRECOMPUTED OFFLINE via batch graph processing and served from cache — turning an infeasible live cross-shard traversal into a cheap cached lookup."),
      C("deep_dive", "Deep dive: graph processing, incremental updates & operations",
        "Operationally the social graph powers many features beyond PYMK and must stay fresh and scalable. Graph-processing infrastructure: PYMK and other graph analytics (mutual friends, community detection, influence, friend recommendations) run on a distributed graph-compute framework (Pregel/Giraph/Spark-GraphX-style vertex-centric computation, or MapReduce jobs) over the whole graph periodically — this batch layer is where heavy traversals live. Incremental / near-real-time updates: nightly batch is stale for active users, so layer incremental updates — when you add a friend, trigger an update to your (and the new friend's) suggestions; stream graph changes to keep hot users' PYMK fresh (a lambda-style mix of batch + streaming). Caching & serving: precomputed suggestions cached per user (and refreshed); the serving path is a simple cache read. Edge consistency: a friendship is bidirectional — adding/removing updates both users' adjacency lists (and may need to stay consistent); follows are one-directional. Supernode handling: high-degree nodes get separate storage/handling (don't load a celebrity's full list into a traversal; sample; exclude their shared-edges from mutual-friend scoring). Privacy: respect blocks, privacy settings, and 'don't suggest me to X' — filter the candidates; PYMK is sensitive (suggesting the wrong person is a known failure mode). Other graph queries: shortest path / degrees of separation, mutual-friends display, and connection-based ranking reuse the same storage. Multi-purpose graph: the same graph feeds the news-feed (whose posts to fan out), recommendations, and ad targeting. Scale/sharding: partition by user; replicate for reads; the batch graph store may be a separate snapshot. Observability: PYMK freshness (recompute lag), suggestion quality (accept rate), 1st/2nd-degree query latency, graph-job runtime, and storage/edge growth are the SLOs. The spine holds: sharded adjacency-list graph + supernode handling + offline batch graph processing (mutual-ranked friends-of-friends) + incremental freshness + cached serving + privacy filtering."),
      C("deep_dive", "Common follow-ups & how it evolves",
        "Expect: 'How do you store billions of edges?' sharded ADJACENCY LISTS (user -> friend ids) in a KV/wide-column store, or a graph DB; partition by user — it can't fit one machine. 'A user's friends?' read their adjacency list (cheap, 1st-degree). 'Friends-of-friends (2nd-degree)?' fans out across shards (read all friends' lists -> ~millions of candidates) — expensive, so don't do it live. 'How is PYMK generated?' friends-of-friends ranked by MUTUAL-connection count (+ shared school/work/contacts) — but PRECOMPUTED OFFLINE via batch graph processing (MapReduce/Pregel) over the whole graph, results cached per user; serving is a cache read. 'Why offline?' the 2nd-degree traversal + mutual aggregation per user is far too expensive on-demand at billions of users. 'Celebrities (supernodes)?' special handling — their huge edge lists explode traversals and 'we both follow a celebrity' is a weak signal, so cap/sample/exclude. 'Freshness?' periodic recompute + incremental updates on new friendships. 'Connected check / degrees of separation?' adjacency lookups / BFS (bounded). 'Graph DB vs KV?' graph DB = native traversals; KV adjacency lists = simpler scale. 'Privacy?' filter blocked/private/dismissed candidates. Each returns to the spine: sharded adjacency-list graph + supernode handling + offline batch-computed mutual-ranked PYMK served cached."),
    ],
    "A social-graph / PYMK design tests storing a billion-node graph as sharded ADJACENCY LISTS (or a graph DB) with cheap 1st-degree queries and expensive cross-shard 2nd-degree traversals (+ supernode handling), and generating 'People You May Know' as friends-of-friends ranked by MUTUAL-connection count (+ signals) PRECOMPUTED OFFLINE via batch graph processing and served from cache (because live 2nd-degree traversal per request is infeasible at scale), with incremental freshness and privacy filtering. The signal is sharded graph storage + offline-precomputed mutual-ranked PYMK, not a live graph traversal per request.",
    [
      G("live_traversal", "Computing friends-of-friends / mutual counts live per request.", "Precompute PYMK offline via batch graph processing (friends-of-friends + mutual-count ranking) and serve cached results.", "Traverses the 2nd-degree neighborhood on each PYMK request; infeasible at billions of users."),
      G("single_machine_graph", "Storing the graph in one relational table with self-joins.", "Shard the graph (adjacency lists by user) across machines; a billion-node graph doesn't fit one machine.", "A single friendships table queried with recursive self-joins; doesn't scale."),
      G("ignore_supernodes", "Traversing through celebrity supernodes naively.", "Special-case supernodes (cap/sample their edges, exclude weak 'shared celebrity' signals) to avoid traversal explosion.", "2nd-degree traversal through a million-edge node explodes / pollutes mutual signals."),
    ],
    0.7, DIAG.socialgraph, "Social graph / PYMK architecture"),

  // ─────────────────────── SHOPPING CART & CHECKOUT ────────────────────────
  TT("sysd_m15", "sysd_m15_t2", 2, "Design a Shopping Cart & Checkout", "design-shopping-cart-checkout",
    ["case-study", "ecommerce", "saga", "consistency"],
    "A shopper adds items to a cart that must persist across devices and weeks, then checks out — and at that instant you must reserve inventory without overselling, charge their card exactly once, and create an order, all-or-nothing, even though payment and inventory live in different systems. How do you design cart + checkout?",
    "Two parts with different consistency needs: the CART is stored per user in a fast, available store (eventually consistent is fine — losing a cart item is tolerable, and it must merge across devices/guest→login); CHECKOUT is the critical TRANSACTION — validate the cart, atomically RESERVE inventory (no overselling), process PAYMENT idempotently (no double-charge), and create the ORDER — orchestrated as a SAGA across services with compensation on failure. Available cart + a reliable consistent checkout saga are the substance.",
    [
      C("requirements", "Requirements",
        "Functional: ADD/REMOVE/update items in a CART that PERSISTS (across sessions and devices, and merges a guest cart into the account on login); CHECKOUT — turn the cart into an ORDER by reserving inventory, taking payment, and recording the order; show order confirmation. Non-functional: the CART should be highly AVAILABLE and low-latency (shoppers add to cart constantly; eventual consistency is acceptable — briefly losing/duplicating a cart item is tolerable), while CHECKOUT must be RELIABLE and CONSISTENT (NO OVERSELLING inventory, NO double-charging the customer, the order created exactly once — money + inventory are at stake), and the system must SCALE. Clarify scope: the cart + checkout flow of an e-commerce system. The defining insight is that the two halves have OPPOSITE consistency requirements: (1) the CART is a high-volume, availability-first store where eventual consistency is fine (a shopper's cart is not money — if a write is briefly lost or a cart is slightly stale, that's acceptable, and availability matters more — you never want 'add to cart' to fail); and (2) CHECKOUT is a consistency-CRITICAL, multi-step transaction spanning multiple services (inventory, payment, orders) where correctness is paramount — you must NOT oversell inventory (atomic reservation, like the flash-sale problem) and NOT double-charge (idempotent payment), and the whole thing must be atomic-ish (all-or-nothing) even though it crosses services that have no shared transaction. So the design centers on an available cart store + a reliable, consistent checkout orchestrated as a distributed transaction (saga)."),
      K("estimation", "Capacity estimation (with numbers)",
        "Cart writes: very high volume (add/remove constantly) -> fast, available store ; eventual ok.\nCart: per-user, small (a list of items) -> KV store keyed by user/session.\nCheckout: far less frequent than cart edits, but CRITICAL (money + inventory).\n  spans: inventory (reserve, no oversell) + payment (idempotent, no double-charge) + orders.\nConsistency: cart eventually consistent (tolerable) ; checkout strongly consistent / reliable.\nTakeaway: optimize the cart for availability (KV, eventual) and the checkout for correctness\n(atomic inventory reserve + idempotent payment + order, orchestrated as a saga)."),
      C("hld", "High-level design",
        "CART: stored per user/session in a fast, highly-AVAILABLE store (a key-value store keyed by user — items as a list), optimized for low-latency add/remove and availability (eventual consistency acceptable). It MERGES a guest/anonymous cart into the user's cart on login, and is consistent across devices (read your cart anywhere). Carts can have soft TTLs and may show current price/availability at view time (the cart is a wish-list, not a reservation — availability is re-checked at checkout). CHECKOUT (the critical path): a multi-step distributed transaction across services — (1) VALIDATE the cart (items still available, current prices), (2) RESERVE INVENTORY atomically for each item (no overselling — the flash-sale atomic-decrement pattern), (3) process PAYMENT via a payment service IDEMPOTENTLY (no double-charge on retries), (4) CREATE the ORDER and confirm, (5) decrement inventory / clear the cart. Because these steps span independent services with no shared ACID transaction, checkout is orchestrated as a SAGA: each step is performed in sequence, and if a later step FAILS, COMPENSATING actions undo the earlier ones (release the inventory reservation, refund/void the payment) — keeping the system consistent without a distributed lock. Idempotency keys make each step safe to retry. Trace it: add items (cart, available) -> checkout -> validate -> reserve inventory (atomic) -> charge (idempotent) -> create order -> confirm; if payment fails after reserving -> compensate (release reservation). Available cart store + a saga-orchestrated checkout (atomic inventory reserve + idempotent payment + order) is the shape."),
      K("api", "API / flow",
        "cart: PUT /cart { add/remove item } -> per-user KV store (available, eventual) ; merge guest->login\ncheckout (saga):\n   1) validate cart (availability, price)\n   2) reserve inventory (atomic, no oversell) [compensate: release]\n   3) charge payment (idempotency key, no double-charge) [compensate: refund/void]\n   4) create order (exactly once) + confirm\n   5) finalize inventory + clear cart\n  failure at any step -> run compensations for completed steps (saga)"),
      K("data_model", "Data model",
        "cart: user/session -> [ items {sku, qty} ] in a KV store (available, eventual) ; TTL ; merge on login\ninventory: per-SKU stock (atomic reserve/decrement — no oversell) + reservations (hold)\npayments: idempotency keys -> charge results (no double-charge)\norders: created on successful checkout (status), exactly once\nsaga state: checkout step progress + compensation tracking (durable)"),
      C("deep_dive", "Deep dive: cart storage (availability-first, eventually consistent)",
        "The cart half is deliberately the OPPOSITE of the checkout half — optimized for AVAILABILITY and low latency, accepting eventual consistency. WHY EVENTUAL IS FINE: a cart is NOT an order and NOT money — it's a transient wish-list; if a cart write is briefly lost, a cart is slightly stale across devices, or an item lingers, that's a minor UX issue, NOT a correctness disaster — and you NEVER want 'add to cart' to fail or be slow (that directly loses sales). So the cart prioritizes AVAILABILITY (always writable/readable) over strong consistency — the classic AP choice (Amazon's original Dynamo was built for exactly this: the shopping cart must always accept writes, even during partitions). STORAGE: a fast, highly-available KEY-VALUE store keyed by user/session, holding the cart as a small list of items (sku + qty) — cheap reads/writes, replicated for availability. CROSS-DEVICE / PERSISTENCE: the cart is tied to the USER (not just a browser), so it persists across sessions and devices (log in on your phone, see the cart from your laptop); a GUEST/anonymous cart (keyed by session) is MERGED into the user's cart on login (combine items, dedupe). CONFLICT HANDLING: because it's eventually consistent and multi-device, concurrent cart edits can conflict — resolve by merging (union of items, max quantities) or last-write-wins per item (a cart is forgiving — merging is usually fine, and the Dynamo cart famously merged divergent versions). The cart does NOT reserve inventory or lock anything — it's just a saved list; ACTUAL availability and price are RE-CHECKED at checkout (so a cart can contain a now-out-of-stock item, surfaced at checkout). TTL: carts may expire after inactivity. So an available, eventually-consistent, user-keyed KV cart that merges across devices/guest-login and re-validates at checkout is the cart core interviewers probe (and the canonical example of choosing availability over consistency)."),
      C("deep_dive", "Deep dive: the checkout transaction (saga: reserve + pay + order)",
        "Checkout is the consistency-CRITICAL half: a multi-step operation across INDEPENDENT services (inventory, payment, orders) that must be reliable and effectively atomic, despite no shared ACID transaction. THE STEPS: validate the cart (items available, prices current), RESERVE INVENTORY for each item, take PAYMENT, CREATE the ORDER, finalize. Two correctness musts: NO OVERSELLING — reserving inventory must be ATOMIC per item (decrement-if-available / conditional update — the flash-sale pattern), so two concurrent checkouts can't both claim the last unit (often a HOLD with a TTL during checkout); and NO DOUBLE-CHARGE — payment must be IDEMPOTENT (an idempotency key per checkout, so a retry/timeout doesn't charge twice), and the order created EXACTLY ONCE. THE DISTRIBUTED-TRANSACTION PROBLEM: these steps span separate services/databases, so you can't wrap them in one ACID transaction (and 2PC across a payment provider is impractical). The standard solution is a SAGA: execute the steps as a SEQUENCE of local transactions, and if a later step FAILS, run COMPENSATING transactions to undo the completed earlier ones — e.g. if payment fails AFTER reserving inventory, COMPENSATE by RELEASING the inventory reservation; if order creation fails after payment, refund/void the payment. This keeps the overall operation consistent (all-or-nothing in effect) without a distributed lock, accepting brief intermediate inconsistency that compensation resolves. The saga is typically ORCHESTRATED (a checkout orchestrator/state-machine drives the steps + compensations, durably tracking progress so it can resume/retry after a crash — the workflow-engine/durable-execution pattern) for reliability. IDEMPOTENCY everywhere makes each step + retry safe. RESERVE-then-CONFIRM with TTL holds (release inventory if checkout is abandoned) handles the time payment takes. So an atomic inventory reservation (no oversell) + idempotent payment (no double-charge) + exactly-once order, orchestrated as a saga with compensation (durable, idempotent, resumable), is the checkout core interviewers probe (and why 'just do the steps and hope' fails across services)."),
      C("bottlenecks", "Bottlenecks & trade-offs",
        "CART AVAILABILITY — never fail 'add to cart' -> available KV store, eventual consistency, merge conflicts. CHECKOUT RELIABILITY/CONSISTENCY across services -> saga with compensation + durable orchestration (no shared ACID transaction). OVERSELLING — atomic inventory reservation (the flash-sale problem) + TTL holds. DOUBLE-CHARGE — idempotent payment (idempotency keys) + exactly-once order. PARTIAL FAILURE — a step fails mid-checkout -> compensations undo prior steps; the orchestrator resumes after crashes. HOT ITEMS / inventory contention at checkout -> atomic decrement serializes (one wins). Trade-offs: available eventually-consistent cart (never blocks shoppers, merges — possible transient inconsistency) vs strongly-consistent cart (consistent — availability/latency cost, unnecessary for a wish-list); saga with compensation (works across services, reliable — intermediate inconsistency + compensation logic) vs 2PC/distributed lock (stronger atomicity — impractical/slow across a payment provider) vs no orchestration (simple — partial-failure corruption); reserve-then-confirm with TTL holds (no oversell during payment — must manage holds) vs charge-first (simpler — oversell/refund risk); idempotency keys (safe retries — must implement) vs naive retries (double-charge/duplicate orders). Closing signal: an available, eventually-consistent, user-keyed cart (merges across devices/guest-login, re-validated at checkout) + a consistency-critical checkout orchestrated as a SAGA — atomic inventory reservation (no oversell, TTL holds) + idempotent payment (no double-charge) + exactly-once order, with compensation on failure and durable resumable orchestration — availability where it's cheap, strict correctness where money/inventory are at stake."),
      C("deep_dive", "Deep dive: pricing, fulfillment, idempotency & operations",
        "Operationally cart + checkout sits at the heart of e-commerce revenue and correctness. Pricing & promotions: the cart shows prices, but the AUTHORITATIVE price/total (with taxes, shipping, discounts/coupons, currency) is computed at checkout by a pricing service — re-validated so a stale cart price isn't honored incorrectly; coupon application must be consistent (one-time codes, limits). Inventory reservation lifecycle: a checkout RESERVES stock with a TTL hold (so a slow payment doesn't oversell, and abandoned checkouts release stock); on order completion the reservation is committed (decremented), on failure/timeout released — atomic + idempotent (the flash-sale/booking pattern). Payment integration: charge via a payment gateway with an idempotency key (retries don't double-charge), handle async results (some payments confirm later — pending state), and support multiple methods; fraud checks (the fraud-detection design) may gate checkout. Order lifecycle: an order is created exactly once and then flows through fulfillment (a workflow — pack, ship, deliver) — the saga can extend into fulfillment with its own compensations (cancel/refund). Saga orchestration & durability: a durable orchestrator (or a workflow engine) drives checkout steps + compensations, persists progress, and resumes after crashes (durable execution) — so a crash mid-checkout neither double-charges nor leaves inventory stuck; in-doubt steps are reconciled. Cart features: save-for-later, wishlists, abandoned-cart recovery (email reminders), and cart merging on login. Scale: cart store (high write volume) and inventory (hot SKUs) scale independently; checkout is lower volume but must be bulletproof. Consistency boundaries: cart = AP (available); inventory/payment/orders = CP (consistent). Observability: add-to-cart success/latency, checkout success/abandonment, oversell incidents (must be zero), double-charge incidents (zero), and saga compensation rates are the SLOs. The spine holds: available eventually-consistent cart + a durable, idempotent, compensating checkout saga (reserve inventory + pay + create order) with authoritative pricing and fulfillment hand-off."),
      C("deep_dive", "Common follow-ups & how it evolves",
        "Expect: 'Cart consistency?' availability-first / eventually consistent — a cart is a wish-list, not money; never fail 'add to cart'; store per-user in an available KV store, merge conflicts and guest->login (the classic Dynamo cart). 'Persist across devices?' key the cart to the USER (not the browser); read it anywhere; merge guest cart on login. 'Checkout across inventory + payment + orders without a shared transaction?' a SAGA — sequence the local steps, and on failure run COMPENSATIONS (release inventory, refund) — orchestrated durably (resumes after crashes). 'No overselling?' atomic inventory reservation (decrement-if-available / TTL hold) — the flash-sale pattern. 'No double-charge?' idempotent payment (idempotency key) + exactly-once order. 'Payment takes time / abandoned checkout?' reserve a TTL hold; release on timeout. 'Crash mid-checkout?' durable saga state -> resume/reconcile (no double-charge, no stuck inventory). 'Stale cart price/availability?' re-validate at checkout (authoritative pricing); the cart isn't a reservation. 'Coupons/taxes/shipping?' computed authoritatively at checkout. 'Concurrent cart edits across devices?' merge (union/LWW per item). Each returns to the spine: available eventually-consistent cart + a durable, idempotent, compensating checkout saga (reserve inventory + idempotent pay + exactly-once order)."),
    ],
    "Shopping cart + checkout tests recognizing two OPPOSITE consistency needs: an AVAILABILITY-first, eventually-consistent, user-keyed CART (never fail add-to-cart; merge across devices/guest-login; re-validate at checkout — the classic Dynamo AP case) versus a consistency-CRITICAL CHECKOUT orchestrated as a SAGA across inventory/payment/orders — atomic inventory reservation (no oversell), idempotent payment (no double-charge), exactly-once order, with compensation on failure and durable resumable orchestration. The signal is available cart + saga-based reliable checkout, not one strongly-consistent flow for everything.",
    [
      G("strong_cart", "Making the cart strongly consistent / failing add-to-cart on contention.", "Make the cart availability-first (eventually consistent KV, merge conflicts) — a cart is a wish-list; never block shoppers.", "Cart uses strict transactions/locks; 'add to cart' can fail or stall."),
      G("no_saga", "Doing checkout steps across services with no distributed-transaction strategy.", "Orchestrate checkout as a saga — sequence local steps with compensating actions on failure; durable + idempotent.", "Calls inventory + payment + order in sequence with no compensation; partial failures corrupt state."),
      G("nonidempotent_checkout", "Non-idempotent payment / non-atomic inventory in checkout.", "Atomic inventory reservation (no oversell, TTL holds) + idempotent payment (idempotency keys, no double-charge) + exactly-once order.", "Read-then-decrement inventory (oversell) or retried charges (double-charge)."),
    ],
    0.6, DIAG.cart, "Shopping cart & checkout architecture"),

  // ─────────────────────── SUBSCRIPTION BILLING ────────────────────────────
  TT("sysd_m15", "sysd_m15_t3", 3, "Design a Subscription Billing System", "design-subscription-billing",
    ["case-study", "billing", "recurring", "accuracy"],
    "Millions of customers on monthly and annual plans must be charged automatically every cycle — correctly to the cent, never twice, with the right proration when they upgrade mid-month, retrying gracefully when a card declines. Money correctness is non-negotiable. How do you build recurring subscription billing?",
    "Model SUBSCRIPTIONS (plan + cycle + status); a billing ENGINE/scheduler runs each billing CYCLE — generate an invoice and CHARGE via a payment gateway IDEMPOTENTLY (never double-charge); handle PRORATION on mid-cycle plan changes, DUNNING (retry failed payments with grace, then suspend/cancel), and usage metering for usage-based plans — all with an audit trail and reconciliation, because it's money. Recurring billing engine + proration/dunning/accuracy are the substance.",
    [
      C("requirements", "Requirements",
        "Functional: manage PLANS (pricing, billing interval) and SUBSCRIPTIONS (a customer on a plan); automatically CHARGE recurring fees each billing CYCLE; generate INVOICES/receipts; handle plan changes (upgrade/downgrade) with PRORATION; retry FAILED payments (DUNNING); support cancellations, trials, and usage-based/metered billing; report revenue. Non-functional: ACCURACY (it's MONEY — charges must be correct to the cent, never double-charged, never missed), RELIABILITY (every due subscription billed; survive failures without losing/duplicating charges), AUDITABILITY (a clear trail for every charge/refund — financial + regulatory), and SCALE (millions of subscriptions billed per cycle). Clarify scope: a subscription/recurring-billing system (Stripe Billing / Chargebee style). The defining requirement is ACCURACY/CORRECTNESS because it's money: you must charge each subscriber the right amount at the right time EXACTLY ONCE — never double-charge (a retry must not charge twice -> IDEMPOTENCY), never skip a due charge, and get amounts right including PRORATION (partial-period charges when plans change mid-cycle) and taxes. Layered on: RECURRING scheduling (charge on each cycle reliably at scale), DUNNING (cards fail constantly — retry intelligently, then grace/suspend), and (for usage plans) METERING. It combines a reliable scheduler/state-machine + payment integration + financial accuracy/audit. So the design centers on a recurring billing engine + proration/dunning/exactly-once-accuracy."),
      K("estimation", "Capacity estimation (with numbers)",
        "Subscriptions: millions ; each billed per cycle (monthly/annual) -> spiky billing runs.\nCycle run: find subscriptions due today -> generate invoice -> charge via payment gateway.\nAccuracy: charge EXACTLY ONCE (idempotency) ; correct amount (proration, tax, usage).\nDunning: cards fail often (~5-15%) -> retry schedule + grace period -> suspend/cancel.\nAudit: every charge/refund/invoice durably recorded + reconciled (it's money).\nTakeaway: a reliable cycle scheduler + idempotent charging + proration + dunning +\naudit/reconciliation -> accurate recurring billing at scale."),
      C("hld", "High-level design",
        "MODEL: PLANS (price, interval, features) and SUBSCRIPTIONS (customer + plan + status (active/past-due/canceled) + current period + next-bill date), as a state machine. A BILLING ENGINE/SCHEDULER drives the recurrence: each cycle it finds subscriptions DUE (next-bill date reached), generates an INVOICE (line items: subscription fee + proration adjustments + metered usage + taxes), and CHARGES the customer via a PAYMENT GATEWAY — IDEMPOTENTLY (an idempotency key per invoice/charge so a retry or crash never double-charges). On SUCCESS: mark the invoice paid, advance the period, set the next-bill date. On FAILURE (card declined): enter DUNNING — retry the charge on a schedule with a GRACE period, notify the customer to update payment, and after exhausting retries SUSPEND/cancel the subscription. PLAN CHANGES mid-cycle compute PRORATION (credit unused time on the old plan, charge the prorated new plan). USAGE-BASED plans aggregate metered usage into the invoice. Everything is recorded in a durable AUDIT trail (invoices, charges, refunds, state changes) and RECONCILED against the payment provider (it's money). Trace it: cycle job finds Alice due -> invoice ($10) -> charge (idempotent) -> success -> mark paid, next bill +1 month; Bob's card declines -> dunning (retry in 3 days, notify) -> still fails -> suspend. Subscription state machine + cycle scheduler + idempotent invoice/charge + proration + dunning + audit/reconciliation is the shape."),
      K("api", "API / flow",
        "model: plan { price, interval } ; subscription { customer, plan, status, period, next_bill }\ncycle (scheduler): find subscriptions due -> for each:\n   generate invoice (fee + proration + usage + tax) -> charge via gateway (IDEMPOTENCY key)\n   success -> mark paid + advance period ; fail -> DUNNING (retry schedule + grace -> suspend)\nplan change: compute PRORATION (credit old + charge prorated new)\nusage plans: aggregate metered usage -> invoice line item\naudit: record every invoice/charge/refund/state change + reconcile with provider"),
      K("data_model", "Data model",
        "plans: id, price, interval, features\nsubscriptions: customer, plan, status, current_period, next_bill_date (state machine)\ninvoices: line items (fee/proration/usage/tax), amount, status (paid/open/failed)\ncharges: idempotency key -> gateway result (exactly-once)\ndunning: retry attempts/schedule + grace state per failed invoice\nusage (metered plans): aggregated usage per subscription per period\naudit/ledger: every financial event (charge/refund/adjustment) -> reconciliation"),
      C("deep_dive", "Deep dive: the recurring billing engine (cycles, invoices, idempotent charges)",
        "The core is reliably charging the right subscriptions on the right schedule, exactly once. SUBSCRIPTION STATE MACHINE: each subscription tracks its plan, status (trialing/active/past-due/canceled), current billing PERIOD, and NEXT-BILL date — transitions (renew, fail->past-due, recover, cancel) are well-defined. CYCLE SCHEDULER: a recurring job (or per-subscription scheduled events) finds subscriptions whose next-bill date is reached and processes them — this is a large, periodic, somewhat SPIKY workload (many subscriptions due on the 1st of the month), so it's scaled out (parallel workers process due subscriptions) and resilient. INVOICE GENERATION: for each due subscription, generate an INVOICE assembling line items — the base subscription fee, any PRORATION adjustments, accrued METERED usage, discounts/coupons, and TAXES — computing the correct total. CHARGING IDEMPOTENTLY (the accuracy crux): charge the customer via a payment GATEWAY using an IDEMPOTENCY KEY tied to the invoice — so if the billing job retries, the worker crashed after charging but before recording, or a duplicate run occurs, the customer is charged EXACTLY ONCE (the gateway/your records dedupe by the key) — double-charging is a cardinal sin. The charge result updates the invoice (paid/failed) and, on success, ADVANCES the subscription period + sets the next-bill date. RELIABILITY: the billing process must be resumable and idempotent end-to-end (a crash mid-cycle must not skip or double-bill anyone) — often implemented with durable per-subscription billing steps (workflow/durable-execution-like) so each subscription's billing is tracked and safely retried. So a subscription state machine + a scalable cycle scheduler + correct invoice assembly + idempotent (exactly-once) charging + period advancement is the engine core interviewers probe (idempotency is THE point — it's money)."),
      C("deep_dive", "Deep dive: proration, dunning & financial accuracy",
        "Around the engine sit the things that make billing CORRECT and resilient to real-world messiness. PRORATION: when a customer changes plans MID-CYCLE (upgrade/downgrade) you can't just charge the new plan in full — you must PRORATE: credit the UNUSED portion of the old plan's already-paid period and charge the PRORATED amount for the remainder on the new plan (e.g. upgrade halfway through the month -> credit ~half the old fee, charge ~half the new fee, often immediately or on the next invoice) — getting these partial-period calculations right (by days/seconds) is essential for accuracy and customer trust. DUNNING (failed-payment management): a significant fraction of recurring charges FAIL (expired/insufficient cards), so a failed charge doesn't immediately cancel — it enters DUNNING: a RETRY schedule (retry over several days, when funds/new cards may appear — 'smart retries'), customer NOTIFICATIONS to update payment, a GRACE period where service continues (past-due), and finally SUSPENSION/cancellation if all retries fail — this recovers revenue that would otherwise be lost and handles the reality of card failures gracefully. FINANCIAL ACCURACY & AUDIT: because it's MONEY, every financial event (invoice, charge, refund, credit, adjustment) is recorded in an immutable AUDIT trail / LEDGER, charges are EXACTLY-ONCE (idempotency), and the system RECONCILES its records against the PAYMENT PROVIDER (and accounting) to catch discrepancies — you must always be able to explain every cent. EXACTLY-ONCE / idempotency is reinforced everywhere (no double-charge, no duplicate invoice). EDGE CASES the system must handle correctly: refunds/credits, cancellations (immediate vs end-of-period), trials converting to paid, currency, taxes (jurisdiction-specific), and partial refunds. So proration (correct partial-period math) + dunning (intelligent failed-payment retries + grace) + a financial audit trail/reconciliation with exactly-once charging is what makes billing accurate and robust — exactly what interviewers probe (it's the part that separates a real billing system from 'charge the card every month')."),
      C("bottlenecks", "Bottlenecks & trade-offs",
        "ACCURACY (money) is paramount — exactly-once charging (idempotency keys), correct amounts (proration/tax/usage), audit + reconciliation; double-charging or wrong amounts are unacceptable. RELIABILITY of the cycle — every due subscription billed, no skips/dupes despite crashes -> durable, resumable, idempotent per-subscription billing. BILLING SPIKES (many due on the 1st) -> scale out workers; spread/schedule. DUNNING — high card-failure rate -> smart retry schedules + grace (recover revenue) without annoying/over-charging. PRORATION correctness -> precise partial-period math. PAYMENT-PROVIDER dependency/failures -> retries + reconciliation + async result handling. Trade-offs: idempotent exactly-once charging (no double-charge — must implement keys/dedup) vs naive retries (simple — double-charge risk, fatal); durable per-subscription billing/workflow (resumable, no skip/dupe on crash — more machinery) vs a simple cron loop (simple — crash can skip/double-bill); smart dunning retries + grace (recovers revenue, good UX — complexity) vs immediate cancel on failure (simple — lost revenue, churn); proration (fair, accurate — complex math) vs charge-full-on-change (simple — wrong/unfair); strong audit/reconciliation (correct, compliant — overhead) vs trust-the-gateway (simpler — unexplained discrepancies). Closing signal: a subscription state machine + a scalable, durable, idempotent (EXACTLY-ONCE) cycle billing engine that generates correct invoices (proration + usage + tax), charges via a payment gateway, handles failed payments with dunning (smart retries + grace -> suspend), and records everything in an audited ledger reconciled with the provider — accurate, reliable recurring billing where money correctness is non-negotiable."),
      C("deep_dive", "Deep dive: usage metering, taxes, lifecycle & operations",
        "Operationally subscription billing is financial infrastructure where correctness and auditability dominate. Usage-based / metered billing: for usage plans (per-API-call, per-seat, per-GB), METER usage events (an ingestion + aggregation pipeline, like the ad-aggregator — accuracy matters because it's billed), aggregate per subscription per period, and add it to the invoice; rate it by the plan's pricing tiers. Tax & compliance: compute taxes/VAT by jurisdiction (often via a tax service), handle invoicing requirements, and retain records for financial/regulatory audit; revenue recognition for accounting. Lifecycle & state transitions: trials (and trial->paid conversion), upgrades/downgrades (with proration), pauses, cancellations (immediate vs end-of-period, with proration/refund policy), and reactivation — a well-defined subscription state machine drives these. Idempotency & reconciliation: idempotency keys on every charge; periodic reconciliation between your ledger, the payment provider, and accounting to detect/repair discrepancies (the source of truth must be defensible). Dunning sophistication: smart retry timing (retry when payday/likely funds), card-updater services (auto-update expired cards), and configurable grace/suspension policies — directly impacting revenue retention. Notifications: receipts, upcoming-charge reminders, payment-failed/dunning emails, and renewal notices. Resilience: the billing run is durable and resumable (workflow-engine-like per-subscription) so partial failures neither skip nor double-bill; failed external calls retry idempotently. Multi-currency & pricing changes: handle currency, plan price changes (grandfathering), coupons/discounts/credits. Scale: process millions of due subscriptions per cycle in parallel; the metering pipeline scales separately. Observability: billing success rate, double-charge/skip incidents (must be zero), dunning recovery rate, reconciliation discrepancies, and invoice-generation latency are the SLOs. The spine holds: subscription state machine + durable idempotent cycle engine + correct invoicing (proration/usage/tax) + dunning + audited reconciled ledger."),
      C("deep_dive", "Common follow-ups & how it evolves",
        "Expect: 'How do you never double-charge?' IDEMPOTENT charging — an idempotency key per invoice/charge so retries, crashes, or duplicate runs charge exactly once; it's money, so exactly-once is the bar. 'How do you bill reliably each cycle?' a subscription state machine + a scalable cycle scheduler that finds due subscriptions and bills them via durable, resumable, idempotent per-subscription steps (no skip/dupe on crash). 'Plan change mid-cycle?' PRORATION — credit the unused old-plan time and charge the prorated new plan (precise partial-period math). 'Card declines?' DUNNING — retry on a smart schedule with a grace period + notify the customer to update payment, then suspend/cancel if it keeps failing (recovers revenue). 'Usage-based plans?' meter usage events, aggregate per period, add to the invoice (accurate metering). 'Taxes?' compute by jurisdiction (tax service). 'Auditability?' an immutable ledger of every charge/refund/adjustment + reconciliation with the payment provider (explain every cent). 'Cancellation/refund?' state transitions with proration/refund policy. 'Billing-day spike?' scale out workers across due subscriptions. Each returns to the spine: subscription state machine + durable idempotent (exactly-once) cycle engine + correct invoicing (proration/usage/tax) + dunning + audited reconciled ledger."),
    ],
    "A subscription billing system tests money-grade ACCURACY: a subscription state machine + a scalable, durable, IDEMPOTENT (exactly-once) cycle engine that generates correct invoices (PRORATION on plan changes + metered usage + tax) and charges via a payment gateway, with DUNNING (smart retries + grace → suspend) for failed cards and an audited, reconciled LEDGER — never double-charging, never skipping, always explainable. The signal is recurring engine + idempotency + proration/dunning/audit, not 'charge the card every month'.",
    [
      G("nonidempotent_charge", "Charging without idempotency (retries can double-charge).", "Use idempotency keys per invoice/charge so retries/crashes/duplicate runs charge exactly once — it's money.", "Retries or crash-recovery re-charge the customer; double-billing."),
      G("no_dunning", "Canceling immediately on a failed payment (no retry strategy).", "Implement dunning — smart retries + grace period + notifications, then suspend; recovers revenue from transient card failures.", "A single declined charge cancels the subscription; lost revenue + churn."),
      G("no_proration_audit", "Ignoring proration on plan changes / no audit & reconciliation.", "Prorate partial periods correctly and keep an immutable ledger reconciled with the provider — explain every cent.", "Charges full price on mid-cycle changes; no audit trail/reconciliation."),
    ],
    0.6, DIAG.billing, "Subscription billing architecture"),

  // ─────────────────────────── MATCHMAKING SERVICE ─────────────────────────
  TT("sysd_m14", "sysd_m14_t6", 6, "Design a Matchmaking Service", "design-matchmaking",
    ["case-study", "gaming", "matching", "tradeoff"],
    "An online game must group waiting players into fair, balanced matches — similar skill, low ping, full teams — fast enough that no one stares at a 'searching…' screen. But the fairest match (perfectly equal skill, lowest latency) might take forever to assemble. How do you balance match quality against wait time at scale?",
    "Players enter a matchmaking QUEUE tagged with attributes (SKILL rating/MMR, region, latency); the matchmaker forms matches by grouping players of SIMILAR SKILL within latency/region constraints. The defining tension is match QUALITY (tight skill range, low ping) vs WAIT TIME — solved by WIDENING the acceptable skill/latency window the longer a player waits, so they aren't stuck. Then it allocates a game server. Skill-based matching + the quality-vs-wait-time trade-off at scale are the substance.",
    [
      C("requirements", "Requirements",
        "Functional: place players into MATCHES — group the right NUMBER of players into balanced teams of SIMILAR skill, respecting region/latency, then start the game (allocate a server); support different modes/team sizes; handle parties (groups queuing together). Non-functional: MATCH QUALITY (balanced, similar-skill, low-latency matches — for fun, fair games), LOW WAIT TIME (players shouldn't wait long in the queue), FAIRNESS, and SCALE (many concurrent players queuing). Clarify scope: the matchmaking service for an online game (forms matches; pairs with the game-server allocation). The defining challenge is the fundamental TRADE-OFF between MATCH QUALITY and WAIT TIME: the IDEAL match has players of nearly identical SKILL (so games are competitive/fun, not stomps) with low LATENCY (same region) and full teams — but assembling a perfect match can take a long time (you might wait forever for an exact skill peer in your region), and players HATE waiting; conversely, matching anyone instantly gives terrible, unbalanced games. So matchmaking must BALANCE these: start with strict criteria (tight skill range, low ping) and RELAX them the longer a player waits, accepting a slightly worse match rather than an endless queue. Layered on: SKILL RATING (how to measure skill — MMR/ELO), regional/latency pools, party handling, and then SERVER ALLOCATION. So the design centers on skill-based matching + the quality-vs-wait-time trade-off (widening windows) at scale."),
      K("estimation", "Capacity estimation (with numbers)",
        "Players: many concurrent in queue, partitioned by mode + region.\nQueue attributes: skill (MMR/ELO), region, latency, party.\nMatch: group N players (team size) of similar skill within a latency window.\nTrade-off: tight skill window = better match but longer wait ; widen over time.\n  e.g. start +-50 MMR, widen +25 every 10s until a match forms (bound wait time).\nPools: per region/mode (low-population pools = longer waits / wider windows).\nTakeaway: queue by skill/region/latency ; match similar skill ; WIDEN the acceptable\nwindow as wait grows (quality vs wait) ; then allocate a game server."),
      C("hld", "High-level design",
        "Players request a match and enter a matchmaking QUEUE (partitioned by game MODE and REGION), tagged with attributes: their SKILL rating (MMR/ELO), region, measured LATENCY/ping, and party (if grouped). The MATCHMAKER continuously scans the queue and forms MATCHES — selecting a set of players that (a) fills the required team size, (b) has SIMILAR skill (within an acceptable MMR window, balanced across teams), and (c) meets LATENCY/region constraints. The CRUCIAL mechanism is the QUALITY-vs-WAIT trade-off: each waiting player has an acceptable skill/latency WINDOW that WIDENS the longer they wait — so a player who's waited a while will be matched with a broader skill range (or higher ping) rather than waiting indefinitely — bounding wait time at the cost of some match quality. Once a valid group is formed, the matchmaker creates the MATCH, assigns teams (balancing skill), and ALLOCATES a GAME SERVER (near the players, for latency — the game-server design) for them to play on; after the game, results update players' skill ratings (feeding future matchmaking). LOW-POPULATION pools (off-hours, niche modes) inherently mean wider windows / longer waits. Trace it: player queues (MMR 1500, NA) -> matchmaker looks for ~9 others near 1500 in NA -> not enough -> window widens as they wait -> forms a balanced 5v5 -> allocate a server -> play -> update MMR. Skill/region/latency queue + matchmaker grouping similar skill with widening windows + server allocation is the shape."),
      K("api", "API / flow",
        "queue: player joins matchmaking { mode, region, MMR/skill, latency, party }\nmatchmaker (loop): scan queue -> find a group of team-size with SIMILAR skill + latency/region\n   acceptable window WIDENS with wait time (quality vs wait)\n   form match -> balance teams -> allocate game server (near players)\nrating: after match -> update players' MMR/ELO (feeds future matchmaking)\npools: partitioned by mode + region ; low-population -> wider windows / longer waits"),
      K("data_model", "Data model",
        "queue entries: player, skill (MMR/ELO), region, latency, party, wait_time, current window\nmatches: grouped players, balanced teams, assigned game server\nskill ratings: per-player MMR/ELO (updated by results)\npools: per mode + region\nparameters: window-widening schedule, team size, latency limits"),
      C("deep_dive", "Deep dive: skill-based matching",
        "The first pillar is matching by SKILL so games are balanced and fun. SKILL RATING: each player has a numeric skill rating — an MMR (matchmaking rating), typically an ELO-style or more advanced system (Glicko, TrueSkill) — that estimates their skill and updates after each game (win vs a stronger opponent -> bigger gain; TrueSkill also tracks uncertainty, narrowing as you play more). This rating is the primary matching signal. MATCHING SIMILAR SKILL: the matchmaker groups players whose ratings are CLOSE (within an acceptable window), so matches are competitive — you face peers, not stomps in either direction (a huge skill gap makes the game un-fun for everyone). For team modes, it also BALANCES teams — distributing players so the two teams have ~equal aggregate/average skill (not just similar individuals), so the match is fair team-vs-team. CONSTRAINTS beyond skill: matches must respect TEAM SIZE (fill all slots), REGION/LATENCY (players should have low ping to each other / the server — high latency ruins gameplay), and sometimes role/composition requirements (e.g. don't put 5 of the same role). PARTIES: friends queue together as a group and must be kept together and matched as a unit (using the party's combined skill), which complicates grouping. SELECTION: the matchmaker searches the queue for a set of players satisfying all constraints — conceptually finding a compatible group (a constraint-satisfaction/optimization over the waiting pool), often greedily (match the longest-waiting players first / expand from a seed player). RATING FEEDBACK: results feed back to update MMR, so matchmaking improves as ratings converge to true skill. So a per-player skill rating (MMR/ELO/TrueSkill, updated by results) + grouping similar-skill players into balanced teams within size/region constraints (handling parties) is the matching core interviewers probe (it's why 'just match the next N players' gives bad games)."),
      C("deep_dive", "Deep dive: the quality-vs-wait-time trade-off & scale",
        "The defining engineering insight is balancing MATCH QUALITY against WAIT TIME — you cannot maximize both. A perfect match (identical skill, lowest ping, ideal composition) might require waiting a long time for the right players to be in the queue simultaneously, but players are impatient (a long 'searching…' is a top complaint and drives quit); matching instantly with anyone gives fast but lopsided, un-fun games. The standard solution is RELAXING CRITERIA OVER TIME (widening windows): each waiting player starts with STRICT acceptance criteria (a tight skill window, e.g. ±50 MMR, low latency, same region) and, the LONGER they wait, the criteria WIDEN (the acceptable skill range grows, latency tolerance increases, maybe cross-region allowed) — so a player is matched quickly if good peers are available, but if not, they progressively accept a slightly worse match rather than waiting forever; this BOUNDS wait time while keeping most matches high-quality (most match fast at tight criteria; only the unlucky widen). The widening schedule (how fast, to what limit) is tuned per the population and acceptable wait. POPULATION effects: match quality + wait depend on QUEUE POPULATION — a healthy, large pool gives fast, tight matches; LOW-POPULATION pools (off-peak, niche modes, very-high-skill players who have few peers) force wider windows / longer waits / merged pools — a real operational constraint. REGIONAL POOLS: queues are partitioned by region (for latency), but small regions may merge or accept higher latency. SCALE: many concurrent players across modes/regions -> shard the matchmaker by pool; the matching loop must efficiently search large queues (indexing by skill). SERVER ALLOCATION: once matched, allocate a game server near the players (the game-server design). So the quality-vs-wait trade-off resolved by time-based criteria-widening (+ handling low-population pools, regional partitioning, and scaling the matcher) is the heart of matchmaking — exactly what interviewers probe (the wrong answer ignores the trade-off)."),
      C("bottlenecks", "Bottlenecks & trade-offs",
        "QUALITY vs WAIT TIME is the core tension — tight criteria = better matches but longer waits; resolve by widening windows over wait time (bound the wait, accept slightly worse matches). LOW-POPULATION POOLS — off-hours/niche modes/extreme-skill players have few peers -> longer waits / wider windows / merged pools (sometimes against bots). LATENCY — players need low ping -> regional pools + latency constraints (relaxed only as a last resort). FAIRNESS/balance — avoid stomps -> similar-skill + balanced teams; smurfs/new-player uncertainty complicate ratings. SCALE of the matcher — large queues searched continuously -> shard by pool, index by skill. PARTIES — groups must stay together (combined skill), harder to place. Trade-offs: tight criteria (great matches — long waits) vs loose (instant — unbalanced) -> widen over time (the balance); skill-balanced (fun, fair — needs accurate MMR + search) vs first-come (instant — bad games); regional pools (low latency — smaller pools/longer waits) vs global (fast matches — high ping); widening schedule aggressive (short waits — more quality sacrifice) vs gentle (better matches — longer waits); ELO vs TrueSkill (uncertainty-aware, better for new players — more complex). Closing signal: queue players by skill (MMR/ELO/TrueSkill) + region/latency, match SIMILAR-skill balanced teams within constraints, and resolve the quality-vs-wait-time trade-off by WIDENING acceptance windows the longer a player waits (bounding wait while keeping most matches high-quality), handling low-population pools and parties, then allocate a regional game server and update ratings from results — fair, fast-enough matchmaking at scale."),
      C("deep_dive", "Deep dive: ratings, fairness, abuse & operations",
        "Operationally matchmaking shapes player experience and retention, so it's heavily tuned. Rating systems: ELO (simple), Glicko (adds rating deviation/uncertainty), and TrueSkill (Bayesian, handles teams + uncertainty, converges fast for new players) — choosing/tuning the system and update rules affects match quality; track uncertainty so new players are matched cautiously and converge quickly. Fairness & integrity: detect SMURFS (skilled players on new accounts — ruin matches), handle new-player onboarding (placement matches, protected pools), discourage rating manipulation/win-trading, and balance teams to minimize blowouts; some systems add role/position matching. Wait-time UX: show estimated wait, allow background queuing, and tune widening so the median wait is short; backfill (fill a slot if someone drops). Connection quality: measure each player's latency to candidate servers/regions and prefer low-latency matches; relax latency last. Parties & cross-play: keep parties together (combined skill, sometimes penalized), and handle cross-platform pools (input-based matching). Server allocation: integrate with game-server allocation (spin up/assign a server near the matched players — the game-server design) and handle allocation failures. Pool management: partition by mode/region/skill-tier; merge or adjust pools dynamically by population (off-peak); special handling for high-MMR (tiny pools). Anti-abuse: dodge/leave penalties, queue dodging, and quitting handling. Telemetry-driven tuning: continuously A/B test matchmaking parameters (window schedules, balance algorithms) against match-quality + wait-time + retention metrics. Scale: shard the matcher by pool; the matching loop indexes the queue by skill for efficient grouping. Observability: average/percentile wait time, match quality (skill spread, blowout rate), match-found rate, pool populations, and post-match rating churn are the SLOs. The spine holds: skill-rated queue + similar-skill balanced matching with time-widening windows + regional/latency pools + party handling + server allocation + rating updates, continuously tuned."),
      C("deep_dive", "Common follow-ups & how it evolves",
        "Expect: 'How do you balance match quality vs wait time?' the core trade-off — start with strict criteria (tight skill window, low latency) and WIDEN the acceptable window the longer a player waits, so they're matched quickly when peers exist but progressively accept slightly worse matches rather than waiting forever (bounds wait time). 'How do you match by skill?' a per-player rating (MMR — ELO/Glicko/TrueSkill, updated by results, ideally with uncertainty), grouping similar-skill players and BALANCING teams to avoid stomps. 'Constraints?' team size, region/latency (low ping), parties (kept together, combined skill). 'Low-population pools (off-hours, high MMR)?' longer waits / wider windows / merged pools (or bots) — population drives quality+wait. 'New players / smurfs?' uncertainty-aware ratings (TrueSkill), placement matches, smurf detection. 'After matching?' allocate a regional game server (game-server design); update ratings from the result. 'Scale the matcher?' shard by pool, index the queue by skill for efficient grouping. 'Someone leaves?' backfill + dodge/leave penalties. 'Tune it?' A/B test widening schedules + balance algorithms against wait + quality + retention. Each returns to the spine: skill-rated queue + similar-skill balanced matching with time-widening windows + regional pools + server allocation + rating updates."),
    ],
    "A matchmaking service tests skill-based matching (per-player MMR/ELO/TrueSkill, grouping similar-skill players into balanced teams within region/latency/size constraints, handling parties) and — the defining insight — resolving the MATCH-QUALITY vs WAIT-TIME trade-off by WIDENING acceptance windows the longer a player waits (bounding wait while keeping most matches high-quality), while handling low-population pools, then allocating a regional game server and updating ratings from results. The signal is skill-based matching + the quality-vs-wait widening-window trade-off, not 'group the next N players'.",
    [
      G("ignore_tradeoff", "Either matching instantly (bad games) or insisting on perfect matches (endless waits).", "Resolve the quality-vs-wait trade-off: start strict, then WIDEN the acceptance window the longer a player waits.", "Fixed criteria with no widening; players wait forever or get lopsided matches."),
      G("no_skill_rating", "Grouping the next N available players regardless of skill.", "Match by a skill rating (MMR/ELO/TrueSkill) and balance teams — similar-skill matches are fair/fun.", "Matches purely by queue order/availability; stomps and unbalanced teams."),
      G("ignore_latency_pools", "Ignoring region/latency and low-population effects.", "Partition pools by region/latency (low ping); handle low-population pools with wider windows / merged pools.", "Matches globally without latency constraints; ignores small-pool wait problems."),
    ],
    0.6, DIAG.matchmaking, "Matchmaking service architecture"),
];

// ── 3 exercises per topic ────────────────────────────────────────────────────
const xpFor = (l) => (l === "warmup" ? 5 : l === "easy" ? 10 : l === "medium" ? 15 : 20);
const diffFor = (l) => (l === "warmup" ? 0.1 : l === "easy" ? 0.2 : l === "medium" ? 0.4 : 0.6);
function pm(moduleId, o) {
  return { trackKey: TRACK_KEY, moduleId, topicId: o.topicId, exerciseId: o.exerciseId,
    position: o.position, level: o.level, type: "pattern_match", title: o.title, scenario: o.scenario,
    instructions: "Pick the best answer.", starterCode: "", expectedSolution: o.correct,
    blanks: [{ options: o.options }], testCases: [{ type: "pattern_match", correct: o.correct, explanation: o.explanation }],
    hints: [], xpReward: xpFor(o.level), difficulty: diffFor(o.level) };
}

